1	const PROCESSING_FEE = 5;
2	
3	const MAIN_ITEM_PREMIUMS: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	  staff: 80,
7	  potion: 40,
8	};
9	
10	const COMPONENT_PREMIUM = 25;
11	const COMPONENT_BLOCK_PREMIUM = 60;
12	const COMPONENT_BLOCK_SIZE = 3;
13	
14	const isComponent = (type: string): boolean => !MAIN_ITEM_PREMIUMS.hasOwnProperty(type);
15	
16	const CURSED_SURCHARGE_RATE = 0.5;
17	const HIGH_ENCHANTMENT_THRESHOLD = 5;
18	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
19	
20	const calculateMainItemPremium = (item: { type: string; cursed?: boolean; enchantment?: number }): number => {
21	  const base = MAIN_ITEM_PREMIUMS[item.type] ?? 0;
22	  let premium = base;
23	  if (item.cursed) {
24	    premium += base * CURSED_SURCHARGE_RATE;
25	  }
26	  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) {
27	    premium += base * HIGH_ENCHANTMENT_SURCHARGE_RATE;
28	  }
29	  return premium;
30	};
31	
32	const calculateComponentGroupPremium = (count: number): number =>
33	  count === COMPONENT_BLOCK_SIZE ? COMPONENT_BLOCK_PREMIUM : count * COMPONENT_PREMIUM;
34	
35	const FIRST_INSURANCE_RATE = 0.1;
36	
37	const calculatePremium = (items: { type: string; cursed?: boolean; enchantment?: number }[]): number => {
38	  let policyBasePremium = 0;
39	  let itemSurcharges = 0;
40	
41	  const componentCounts: Record<string, number> = {};
42	  for (const item of items) {
43	    if (isComponent(item.type)) {
44	      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
45	    } else {
46	      const base = MAIN_ITEM_PREMIUMS[item.type] ?? 0;
47	      policyBasePremium += base;
48	      itemSurcharges += calculateMainItemPremium(item) - base;
49	    }
50	  }
51	
52	  for (const count of Object.values(componentCounts)) {
53	    policyBasePremium += calculateComponentGroupPremium(count);
54	  }
55	
56	  const policyModifiers = policyBasePremium * FIRST_INSURANCE_RATE;
57	
58	  return Math.ceil(policyBasePremium + itemSurcharges + policyModifiers + PROCESSING_FEE);
59	};
60	
61	export function processScenario(scenario: { steps: { op: string; items?: { type: string }[] }[] }): { results: unknown[] } {
62	  const results = scenario.steps.map((step) => {
63	    const premium = calculatePremium(step.items ?? []);
64	    return { premium };
65	  });
66	  return { results };
67	}
